def estimate_difficulty(task, classifier) -> float:
    """Cheap upfront score (0..1) used to allocate model tier and budget."""
    return classifier.score(task)                 # a small model or heuristic

def allocate(task, classifier):
    d = estimate_difficulty(task, classifier)
    if d < 0.3:
        return {"model": "cheap", "max_tokens": 512, "samples": 1}
    if d < 0.7:
        return {"model": "cheap", "max_tokens": 1024, "samples": 1, "escalate": True}
    return {"model": "frontier", "max_tokens": 2048, "samples": 3}   # verify-and-vote

def expected_cost(escalation_rate, c_cheap, c_expensive, c_verify):
    """Cascade cost: everyone pays cheap; only the escalating fraction pays more."""
    return c_cheap + escalation_rate * (c_expensive + c_verify)
